import React from "react";
import "./Section.css";
// Removed 'useNavigate' import as it's not used here

function Pathology() {
  return (
    <div className="full-page-content">
      <div className="section-card">
        <div className="icon">🔬</div>
        <h3>Pathology Services</h3>
        <p>Find and book appointments with leading pathology labs for accurate diagnostics.</p>
        <p>This is the full Pathology Services page content.</p>
      </div>
    </div>
  );
}

export default Pathology;
